"use client";

import { useMemo, useState, useEffect, useRef } from "react";
import { motion } from "framer-motion";
import {
  Sun,
  ArrowUp,
  ArrowDown,
  Maximize2,
  Minimize2,
  Sparkles,
  SlidersHorizontal,
} from "lucide-react";

type DeviceState = {
  motorPosition: number;
  currentSteps: number;
  als: number;
  uvs: number;
  automode: boolean;
};

const WS_URL =
  process.env.NEXT_PUBLIC_ESP_WS_URL || "ws://192.168.0.23:81";

export default function GestureBlindDashboard() {
  const [deviceState, setDeviceState] = useState<DeviceState>({
    motorPosition: 0,
    currentSteps: 0,
    als: 0,
    uvs: 0,
    automode: false,
  });

  const [connected, setConnected] = useState(false);
  const wsRef = useRef<WebSocket | null>(null);

  const blindLevel = deviceState.motorPosition;
  const autoMode = deviceState.automode;

  const clamp = (value: number, min: number, max: number) =>
    Math.min(Math.max(value, min), max);

  const sendMessage = (payload: object) => {
    const ws = wsRef.current;
    if (!ws || ws.readyState !== WebSocket.OPEN) return;
    ws.send(JSON.stringify(payload));
  };

  useEffect(() => {
    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;

    const connect = () => {
      const ws = new WebSocket(WS_URL);
      wsRef.current = ws;

      ws.onopen = () => {
        console.log("WebSocket connected");
        setConnected(true);
        ws.send(JSON.stringify({ type: "requestState" }));
      };

      ws.onmessage = (event) => {
        try {
          const data = JSON.parse(event.data);

          if (data.type === "state") {
            setDeviceState({
              motorPosition: Number(data.motorPosition ?? 0),
              currentSteps: Number(data.currentSteps ?? 0),
              als: Number(data.als ?? 0),
              uvs: Number(data.uvs ?? 0),
              automode: Boolean(data.automode),
            });
          } else if (data.type === "error") {
            console.error("ESP error:", data.message);
          } else {
            console.log("Unknown message:", data);
          }
        } catch (error) {
          console.error("Invalid WebSocket message:", error);
        }
      };

      ws.onclose = () => {
        console.log("WebSocket disconnected");
        setConnected(false);
        reconnectTimer = setTimeout(connect, 2000);
      };

      ws.onerror = (error) => {
        console.error("WebSocket error:", error);
        ws.close();
      };
    };

    connect();

    return () => {
      if (reconnectTimer) clearTimeout(reconnectTimer);
      wsRef.current?.close();
    };
  }, []);

  const increment = () => {
    sendMessage({ type: "incrementBlind", value: 1000 });
  };

  const decrement = () => {
    sendMessage({ type: "decrementBlind", value: 1000 });
  };

  const openAll = () => {
    sendMessage({ type: "openBlind" });
  };

  const closeAll = () => {
    sendMessage({ type: "closeBlind" });
  };

  const toggleAutoMode = () => {
    sendMessage({ type: "setAutomode", value: !autoMode });
  };

  const setBlindPosition = (value: number) => {
    sendMessage({ type: "setMotorPosition", value });
  };

  const slatCount = 9;
  const closedCoverage = 100 - blindLevel;

  const roomGlow = useMemo(() => {
    const value = blindLevel * 0.8 + Math.min(deviceState.als / 600, 100) * 0.2;
    return clamp(value, 10, 100);
  }, [blindLevel, deviceState.als]);

  return (
    <div className="min-h-screen bg-neutral-950 text-white px-4 py-8 sm:px-6 lg:px-8">
      <div className="mx-auto grid max-w-7xl gap-6 lg:grid-cols-[1.2fr]">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5 }}
          className="rounded-3xl border border-white/10 bg-white/5 p-5 shadow-2xl backdrop-blur-xl sm:p-7"
        >
          <div className="mb-6 flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
            <div>
              <div className="mb-2 inline-flex items-center gap-2 rounded-full border border-white/10 bg-white/5 px-3 py-1 text-xs text-white/70">
                <Sparkles className="h-4 w-4" />
                Smart Blind Control
              </div>
              <h1 className="text-3xl font-semibold tracking-tight sm:text-4xl">
                Gesture Controlled Window Blind
              </h1>
              <p className="mt-2 max-w-xl text-sm text-white/65 sm:text-base">
                Live dashboard connected to the ESP32 over WebSocket.
              </p>
            </div>

            <div className="grid grid-cols-2 gap-3 sm:w-70">
              <div className="rounded-2xl border border-white/10 bg-black/20 p-3">
                <p className="text-xs text-white/50">Blind Level</p>
                <p className="mt-1 text-2xl font-semibold">{blindLevel}%</p>
              </div>
              <div className="rounded-2xl border border-white/10 bg-black/20 p-3">
                <p className="text-xs text-white/50">Current Steps</p>
                <p className="mt-1 text-2xl font-semibold">
                  {deviceState.currentSteps}
                </p>
              </div>
            </div>
          </div>

          <div className="grid gap-6 xl:grid-cols-[1fr_0.95fr]">
            <div className="rounded-4xl border border-white/10 bg-linear-to-b from-sky-500/10 via-white/5 to-amber-200/10 p-4 sm:p-6">
              <div className="mb-4 flex items-center justify-between">
                <div>
                  <p className="text-sm text-white/60">Live Animation</p>
                  <p className="text-lg font-medium">Window blind position</p>
                </div>
                <div className="rounded-full border border-white/10 bg-black/20 px-3 py-1 text-xs text-white/70">
                  {blindLevel >= 90
                    ? "Mostly Open"
                    : blindLevel <= 10
                    ? "Mostly Closed"
                    : "Partially Open"}
                </div>
              </div>

              <div className="relative mx-auto flex h-[430px] max-w-[360px] items-center justify-center overflow-hidden rounded-4xl border border-white/10 bg-neutral-900 shadow-inner">
                <motion.div
                  className="absolute inset-0"
                  animate={{ opacity: 0.18 + roomGlow / 140 }}
                  transition={{ duration: 0.4 }}
                >
                  <div className="absolute left-1/2 top-10 h-44 w-44 -translate-x-1/2 rounded-full bg-white blur-3xl" />
                  <div className="absolute inset-x-10 bottom-8 top-28 rounded-3xl bg-linear-to-b from-sky-300/70 via-blue-200/40 to-amber-100/40" />
                </motion.div>

                <div className="absolute left-6 right-6 top-6 bottom-6 rounded-3xl border-4 border-white/20" />
                <div className="absolute left-1/2 top-6 h-8 w-1 -translate-x-1/2 rounded-full bg-white/30" />

                <motion.div
                  className="absolute left-7 right-7 top-7 origin-top rounded-b-[1.2rem] bg-neutral-800/85 backdrop-blur-md"
                  animate={{ height: `${Math.max(closedCoverage * 3.1, 24)}px` }}
                  transition={{ type: "spring", stiffness: 90, damping: 18 }}
                >
                  <div className="h-4 w-full rounded-t-2xl bg-white/10" />
                  <div className="px-2 pt-2">
                    {Array.from({ length: slatCount }).map((_, i) => (
                      <motion.div
                        key={i}
                        className="mb-2 h-5 rounded-md border border-white/5 bg-white/10"
                        animate={{
                          opacity: 0.35 + (closedCoverage / 100) * 0.55,
                        }}
                        transition={{ duration: 0.3 }}
                      />
                    ))}
                  </div>
                </motion.div>

                <motion.div
                  className="absolute right-8 top-7 w-0.5 bg-white/25"
                  animate={{ height: `${110 + closedCoverage * 1.2}px` }}
                  transition={{ type: "spring", stiffness: 100, damping: 20 }}
                />
                <motion.div
                  className="absolute right-[25px] rounded-full border border-white/15 bg-white/10 shadow-lg backdrop-blur-md"
                  animate={{ top: `${100 + closedCoverage * 1.1}px` }}
                  transition={{ type: "spring", stiffness: 100, damping: 20 }}
                  style={{ width: 18, height: 18 }}
                />
              </div>

              <div className="mt-5 rounded-2xl border border-white/10 bg-black/20 p-4">
                <div className="mb-3 flex items-center justify-between">
                  <p className="text-sm text-white/60">Set exact blind position</p>
                  <p className="text-sm text-white/70 font-medium">{blindLevel}%</p>
                </div>

                <input
                  type="range"
                  min="0"
                  max="100"
                  value={blindLevel}
                  onChange={(e) => setBlindPosition(Number(e.target.value))}
                  className="h-2 w-full cursor-pointer appearance-none rounded-full bg-white/15 accent-white"
                />
              </div>
            </div>

            <div className="space-y-5">
              <div className="rounded-4xl border border-white/10 bg-white/5 p-5">
                <div className="mb-4 flex items-center gap-2">
                  <SlidersHorizontal className="h-5 w-5 text-white/70" />
                  <h2 className="text-lg font-medium">Manual Controls</h2>
                </div>

                <div className="grid grid-cols-2 gap-3">
                  <button
                    onClick={increment}
                    className="rounded-2xl border border-white/10 bg-white/10 p-4 text-left transition hover:bg-white/15"
                  >
                    <ArrowUp className="mb-3 h-5 w-5" />
                    <p className="font-medium">Increment</p>
                    <p className="text-sm text-white/55">Raise blind</p>
                  </button>

                  <button
                    onClick={decrement}
                    className="rounded-2xl border border-white/10 bg-white/10 p-4 text-left transition hover:bg-white/15"
                  >
                    <ArrowDown className="mb-3 h-5 w-5" />
                    <p className="font-medium">Decrement</p>
                    <p className="text-sm text-white/55">Lower blind</p>
                  </button>

                  <button
                    onClick={openAll}
                    className="rounded-2xl border border-white/10 bg-linear-to-br from-white/15 to-white/5 p-4 text-left transition hover:scale-[1.01]"
                  >
                    <Maximize2 className="mb-3 h-5 w-5" />
                    <p className="font-medium">Open All</p>
                    <p className="text-sm text-white/55">Set blind to 100%</p>
                  </button>

                  <button
                    onClick={closeAll}
                    className="rounded-2xl border border-white/10 bg-linear-to-br from-white/15 to-white/5 p-4 text-left transition hover:scale-[1.01]"
                  >
                    <Minimize2 className="mb-3 h-5 w-5" />
                    <p className="font-medium">Close All</p>
                    <p className="text-sm text-white/55">Set blind to 0%</p>
                  </button>
                </div>
              </div>

              <div className="rounded-4xl border border-white/10 bg-white/5 p-5">
                <div className="mb-4 flex items-center justify-between gap-3">
                  <div className="flex items-center gap-2">
                    <Sun className="h-5 w-5 text-white/70" />
                    <h2 className="text-lg font-medium">Auto Mode</h2>
                  </div>
                  <button
                    onClick={toggleAutoMode}
                    className={`rounded-full px-3 py-1 text-xs font-medium transition ${
                      autoMode
                        ? "bg-white text-black"
                        : "border border-white/15 bg-white/5 text-white/70"
                    }`}
                  >
                    {autoMode ? "Auto On" : "Auto Off"}
                  </button>
                </div>

                <div className="rounded-2xl border border-white/10 bg-black/20 p-4 space-y-3">
                  <div className="flex items-center justify-between">
                    <p className="text-sm text-white/55">Ambient Light Sensor</p>
                    <div className="rounded-xl border border-white/10 bg-white/10 px-3 py-1 text-lg font-semibold">
                      {deviceState.als}
                    </div>
                  </div>

                  <div className="flex items-center justify-between">
                    <p className="text-sm text-white/55">UV Sensor</p>
                    <div className="rounded-xl border border-white/10 bg-white/10 px-3 py-1 text-lg font-semibold">
                      {deviceState.uvs}
                    </div>
                  </div>
                </div>
              </div>

              <div className="grid gap-4 sm:grid-cols-2">
                <div className="rounded-4xl border border-white/10 bg-white/5 p-5">
                  <p className="text-sm text-white/55">System Status</p>
                  <p className="mt-2 text-xl font-semibold">
                    {connected ? "Online" : "Offline"}
                  </p>
                  <p className="mt-2 text-sm text-white/60">
                    {connected
                      ? "Connected to ESP32 WebSocket."
                      : "Waiting for ESP32 connection."}
                  </p>
                </div>

                <div className="rounded-4xl border border-white/10 bg-white/5 p-5">
                  <p className="text-sm text-white/55">Control Mode</p>
                  <p className="mt-2 text-xl font-semibold">
                    {autoMode ? "Auto" : "Manual"}
                  </p>
                  <p className="mt-2 text-sm text-white/60">
                    {autoMode
                      ? "Blind responds automatically based on sensor readings."
                      : "Blind responds only to manual commands."}
                  </p>
                </div>
              </div>
            </div>
          </div>
        </motion.div>
      </div>
    </div>
  );
}